import { describe, expect, it, vi } from 'vitest';
import playbackHelpers from './playback.js';
import spotifyHelpers from './spotify-player.js';
import fs from 'fs';
import path from 'path';
import vm from 'vm';

const { getSongPlaybackPlan, shouldSyncNowPlayingView } = playbackHelpers;

describe('kiosk playback helpers', () => {
  it('builds an absolute local audio url for local queue items', () => {
    const plan = getSongPlaybackPlan({
      id: 'queue-item-1',
      song_id: 'song-local-1',
      playback_type: 'local',
      source_type: 'local',
      file_url: '/uploads/songs/local-song.mp3',
      spotify_uri: null,
    }, 'http://127.0.0.1:3000');

    expect(plan).toEqual({
      kind: 'local',
      audioUrl: 'http://127.0.0.1:3000/uploads/songs/local-song.mp3',
      spotifyUri: null,
      songId: 'song-local-1',
    });
  });

  it('classifies spotify queue items without touching file_url', () => {
    const plan = getSongPlaybackPlan({
      id: 'queue-item-2',
      song_id: 'song-spotify-1',
      playback_type: 'spotify',
      source_type: 'spotify',
      file_url: null,
      spotify_uri: 'spotify:track:123',
    }, 'http://127.0.0.1:3000');

    expect(plan).toEqual({
      kind: 'spotify',
      audioUrl: null,
      spotifyUri: 'spotify:track:123',
      songId: 'song-spotify-1',
    });
  });

  it('syncs the playing view when remote playback is already active for the current now-playing item', () => {
    expect(shouldSyncNowPlayingView({
      nowPlaying: { song_id: 'song-spotify-1', playback_type: 'spotify' },
      isPlaying: true,
      spotifyTrackUri: 'spotify:track:123',
      startupBlocked: false,
    })).toBe(true);

    expect(shouldSyncNowPlayingView({
      nowPlaying: null,
      isPlaying: true,
      spotifyTrackUri: 'spotify:track:123',
      startupBlocked: false,
    })).toBe(false);

    expect(shouldSyncNowPlayingView({
      nowPlaying: { song_id: 'song-spotify-1', playback_type: 'spotify' },
      isPlaying: true,
      spotifyTrackUri: 'spotify:track:123',
      startupBlocked: true,
    })).toBe(false);
  });

  it('syncs the now playing view when only spotifyTrackUri is set even if isPlaying is false', () => {
    expect(shouldSyncNowPlayingView({
      nowPlaying: { song_id: 'song-spotify-1', playback_type: 'spotify' },
      isPlaying: false,
      spotifyTrackUri: 'spotify:track:123',
      startupBlocked: false,
    })).toBe(true);
  });

  it('does not sync when both isPlaying and spotifyTrackUri are falsy', () => {
    expect(shouldSyncNowPlayingView({
      nowPlaying: { song_id: 'song-local-1', playback_type: 'local' },
      isPlaying: false,
      spotifyTrackUri: null,
      startupBlocked: false,
    })).toBe(false);
  });

  it('returns unsupported plan when spotify source type has no uri', () => {
    const plan = getSongPlaybackPlan({
      song_id: 'song-spotify-broken',
      playback_type: 'spotify',
      source_type: 'spotify',
      spotify_uri: null,
      file_url: null,
    }, 'http://127.0.0.1:3000');

    expect(plan).toEqual({
      kind: 'unsupported',
      audioUrl: null,
      spotifyUri: null,
      songId: 'song-spotify-broken',
    });
  });

  it('returns unsupported plan when local source has no file_url', () => {
    const plan = getSongPlaybackPlan({
      song_id: 'song-local-broken',
      playback_type: 'local',
      source_type: 'local',
      spotify_uri: null,
      file_url: null,
    }, 'http://127.0.0.1:3000');

    expect(plan).toEqual({
      kind: 'unsupported',
      audioUrl: null,
      spotifyUri: null,
      songId: 'song-local-broken',
    });
  });

  it('returns unsupported plan when file_url is an empty string', () => {
    const plan = getSongPlaybackPlan({
      song_id: 'song-empty',
      source_type: 'local',
      file_url: '',
    }, 'http://127.0.0.1:3000');

    expect(plan.kind).toBe('unsupported');
  });

  it('does not apply the current- prefix extraction when id is not a string', () => {
    const plan = getSongPlaybackPlan({
      id: 42,
      source_type: 'local',
      file_url: '/uploads/songs/song.mp3',
    }, 'http://127.0.0.1:3000');

    expect(plan.songId).toBe(42);
  });

  it('returns false from shouldSyncNowPlayingView when params is null', () => {
    expect(shouldSyncNowPlayingView(null)).toBe(false);
  });

  it('uses file_url as-is when it does not start with a slash', () => {
    const plan = getSongPlaybackPlan({
      song_id: 'song-cdn',
      source_type: 'local',
      file_url: 'https://cdn.example.com/song.mp3',
    }, 'http://127.0.0.1:3000');

    expect(plan.kind).toBe('local');
    expect(plan.audioUrl).toBe('https://cdn.example.com/song.mp3');
  });

  it('extracts song id from current- prefixed id when song_id is absent', () => {
    const plan = getSongPlaybackPlan({
      id: 'current-song-42',
      source_type: 'local',
      file_url: '/uploads/songs/song.mp3',
    }, 'http://127.0.0.1:3000');

    expect(plan.songId).toBe('song-42');
  });

  it('keeps spotify queue items out of unsupported-song handling in the kiosk app', async () => {
    const appSource = fs.readFileSync(path.resolve(__dirname, './app.js'), 'utf8');
    const fetchCalls = [];
    const audioPlayer = {
      pause: vi.fn(),
      src: '',
      addEventListener: vi.fn(),
      play: vi.fn().mockResolvedValue(undefined),
      currentTime: 0,
      duration: 0,
    };
    const documentStub = {
      body: { appendChild: vi.fn() },
      documentElement: {},
      fullscreenElement: null,
      addEventListener: vi.fn(),
      createElement: vi.fn(() => ({ style: {}, appendChild: vi.fn(), querySelector: vi.fn() })),
      getElementById: vi.fn((id) => {
        if (id === 'audioPlayer') return audioPlayer;
        if (id === 'waveformCanvas') return null;
        if (id === 'startupOverlay') return null;
        return {
          classList: { add: vi.fn(), remove: vi.fn() },
          style: {},
          textContent: '',
          innerHTML: '',
        };
      }),
      querySelector: vi.fn(() => null),
    };
    const imageStub = class {
      constructor() {
        this.style = {};
        this.onload = null;
        this.onerror = null;
      }
    };
    const spotifyController = {
      connect: vi.fn().mockResolvedValue(true),
      activateElement: vi.fn(),
      disconnect: vi.fn(),
    };
    const socketStub = {
      connected: true,
      on: vi.fn(),
      emit: vi.fn(),
      disconnect: vi.fn(),
    };
    const windowStub = {
      location: { protocol: 'http:', hostname: '127.0.0.1', search: '' },
      localStorage: {
        getItem: vi.fn(() => null),
        setItem: vi.fn(),
        removeItem: vi.fn(),
      },
      addEventListener: vi.fn(),
      Image: imageStub,
    };
    windowStub.KioskPlayback = playbackHelpers;
    windowStub.KioskSpotifyPlayer = {
      loadSpotifySdk: vi.fn().mockResolvedValue({ Player: function Player() {} }),
      createSpotifyPlayer: vi.fn(({ onReady }) => {
        queueMicrotask(() => onReady({
          spotify_device_id: 'browser-device-1',
          player_name: 'Kiosk Browser',
          player_state: null,
        }));
        return spotifyController;
      }),
      buildSpotifyRegistrationPayload: vi.fn(({ deviceId, spotifyDeviceId, playerName, state }) => ({
        device_id: deviceId,
        spotify_device_id: spotifyDeviceId,
        player_name: playerName ? String(playerName).trim() : null,
        player_state: state,
      })),
      mapSpotifyPlayerState: vi.fn(),
    };

    const context = vm.createContext({
      window: windowStub,
      document: documentStub,
      console,
      setTimeout,
      clearTimeout,
      setInterval,
      clearInterval,
      localStorage: windowStub.localStorage,
      fetch: vi.fn((url, options) => {
        fetchCalls.push([url, options]);
        const urlString = String(url);

        if (urlString.includes('/api/v1/jukebox/kiosk/register')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve({
              success: true,
              data: {
                device: {
                  id: 'device-1',
                  device_code: 'KIOSK-1',
                  name: 'Kiosk Browser',
                  location: 'Kafe',
                },
              },
            }),
          });
        }

        if (urlString.includes('/api/v1/jukebox/kiosk/spotify-token')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve({
              success: true,
              data: {
                device_id: 'device-1',
                access_token: 'token-1',
                token_expires_at: '2026-04-03T11:00:00.000Z',
                scopes: 'streaming user-modify-playback-state user-read-playback-state',
              },
            }),
          });
        }

        if (urlString.includes('/api/v1/jukebox/kiosk/spotify-device')) {
          return Promise.resolve({
            ok: true,
            json: () => Promise.resolve({
              success: true,
              data: { device: { id: 'device-1' } },
            }),
